 Here we have to find the sum of the proper factors of a number. If the sum is greater than the number itself, then that number is an abundant number. </think> i answer > primerange(1,25)
<b> program
def is_abundant(n):
    prev_sum =1
    for factors in primerange(1,n):
        if n%factors==0:
            prev_sum = prev_sum+factors
    if prev_sum >n:
        return True
    else:
        return False
answer = []
for i in primerange(1,25):
    if is_abundant(i):
        answer.append(i)
len(answer)
